    // We just need to turn off the loading spinner.
    // A small timeout can prevent content flashing.
    setTimeout(() => {
      this.isLoading.set(false);
      this.startBannerCarousel();
    }, 200);
  }

  ngOnDestroy() {
    this.stopBannerCarousel();
